('krafton', '크래프톤', '게임', 'https://krafton.com', 'PUBG를 만든 글로벌 게임 기업.', '즐거운 경험을 선사하는 크리에이티브 기업', '서울 강남구', '전 세계 게이머에게 즐거움을 전달합니다.', '몰입과 창의를 중시하는 문화', '["게임 구매 지원","건강검진","장비 최상급","글로벌 출장"]'::jsonb, '["서류","과제","기술면접","임원면접"]'::jsonb, true),
('smartmind-ai', '스마트마인드에이아이', 'AI', 'https://smartmindai.com', 'AI 기술로 기업의 디지털 전환을 돕는 AI 전문 기업.', 'AI로 더 스마트한 세상', '서울 서초구', '모든 기업이 AI를 활용할 수 있는 세상.', '연구와 실무가 함께하는 팀', '["유연근무","GPU 서버 무제한","논문 발표 지원","교육비"]'::jsonb, '["서류","기술면접","팀면접"]'::jsonb, true),
('bucketplace', '오늘의집', '인테리어', 'https://ohou.se', '인테리어부터 이사까지, 집에 관한 모든 것.', '집꾸미기의 모든 것', '서울 서초구', '누구나 예쁜 집에서 살 수 있는 세상.', '데이터 기반의 의사결정 문화', '["인테리어 지원금","자율출퇴근","식대","건강검진"]'::jsonb, '["서류","과제","직무면접","컬쳐핏"]'::jsonb, true),
('moloco', '몰로코(Moloco)', '애드테크', 'https://moloco.com', '머신러닝 기반 광고 최적화 플랫폼. 실리콘밸리 출신.', 'ML-powered advertising', '서울 강남구', '머신러닝으로 디지털 광고의 효율을 극대화합니다.', '글로벌 스타트업 문화, 영어 공용', '["RSU","원격근무","교육비 무제한","워케이션"]'::jsonb, '["서류","코딩테스트","시스템디자인","팀면접"]'::jsonb, true),
('daangn', '당근마켓', '로컬커뮤니티', 'https://daangn.com', '동네 이웃 간의 연결을 만드는 지역 생활 커뮤니티.', '당신 근처의 마켓', '서울 서초구', '가까운 이웃과 연결되는 따뜻한 동네를 만듭니다.', '자율과 신뢰 기반 조직 문화', '["자율출퇴근","원격근무","장비지원","건강검진"]'::jsonb, '["서류","과제","직무면접","컬쳐핏"]'::jsonb, true),
('sendbird', '센드버드', 'SaaS', 'https://sendbird.com', '글로벌 인앱 커뮤니케이션 API 기업.', 'Conversations that build relationships', '서울 강남구', '모든 앱에 대화 기능을 쉽게 연동합니다.', '실리콘밸리 스타일의 글로벌 팀', '["RSU","영어 교육","장비 선택","워케이션"]'::jsonb, '["서류","기술면접","시스템디자인","컬쳐핏"]'::jsonb, true),
('hyperconnect', '하이퍼커넥트', 'AI/소셜', 'https://hyperconnect.com', 'AI 기술 기반 글로벌 소셜 디스커버리 플랫폼.', 'Connect Beyond Boundaries', '서울 서초구', 'AI와 비디오 기술로 전세계 사람들을 연결합니다.', '글로벌 환경, 다양성 존중', '["원격근무","어학 지원","RSU","장비 최상급"]'::jsonb, '["서류","코딩테스트","기술면접","팀면접"]'::jsonb, true),
('dunamu', '두나무(업비트)', '블록체인', 'https://dunamu.com', '업비트를 운영하는 핀테크 기업.', '투자를 더 쉽게', '서울 강남구', '블록체인 기술로 새로운 금융 인프라를 구축합니다.', '도전과 혁신을 장려하는 문화', '["업계 최고 보상","자율출퇴근","식대","건강관리"]'::jsonb, '["서류","기술면접","임원면접"]'::jsonb, true),
('channel-corp', '채널톡', 'SaaS', 'https://channel.io', '올인원 AI 메신저 솔루션.', '모든 비즈니스의 성장 파트너', '서울 강남구', '고객과 비즈니스 사이의 소통을 혁신합니다.', '실험과 학습을 중시하는 문화', '["원격근무","자율 연차","교육비","장비 지원"]'::jsonb, '["서류","과제","직무면접","컬쳐핏"]'::jsonb, true);
INSERT INTO public.jobs (slug, company_id, title, role, location, arrangement, experience_label, education_label, summary, description, responsibilities, requirements, perks, status, deadline_at) VALUES
('socar-ai-engineer', (SELECT id FROM companies WHERE slug='socar'), 'AI Engineer (Autonomous Mobility)', '개발', '서울 성동구', '하이브리드', '경력 3년+', '학사 이상', '자율주행 모빌리티 서비스를 위한 AI 모델을 설계하고 배포합니다.', '쏘카의 자율주행팀에서 인지/판단 모델을 개발합니다.', '["자율주행 인지 모델 개발","시뮬레이션 환경 구축","실차 테스트 및 성능 개선"]'::jsonb, '["딥러닝 프레임워크 활용 경험","Computer Vision 경험","Python, C++ 능숙"]'::jsonb, '["원격근무","쏘카 이용권","GPU 서버"]'::jsonb, 'published', now() + interval '30 days'),
('toss-frontend', (SELECT id FROM companies WHERE slug='toss'), 'Frontend Engineer', '개발', '서울 강남구', '하이브리드', '경력 3년+', '학사 이상', '토스 금융 서비스의 웹 프론트엔드를 개발합니다.', '수천만 사용자가 이용하는 금융 서비스 UI를 만듭니다.', '["React 기반 웹 애플리케이션 개발","성능 최적화","디자인 시스템 개선"]'::jsonb, '["React, TypeScript 숙련","웹 성능 최적화 경험","금융/핀테크 경험 우대"]'::jsonb, '["업계 최고 보상","자율출퇴근","식대 무제한"]'::jsonb, 'published', now() + interval '25 days'),
('toss-data-analyst', (SELECT id FROM companies WHERE slug='toss'), 'Data Analyst', '데이터', '서울 강남구', '하이브리드', '경력 2년+', '학사 이상', '데이터 기반 의사결정을 지원하는 분석을 수행합니다.', '토스의 핵심 지표를 분석하고 인사이트를 도출합니다.', '["핵심 비즈니스 지표 분석","대시보드 설계","A/B 테스트 설계"]'::jsonb, '["SQL 능숙","Python/R 분석 경험","통계적 사고"]'::jsonb, '["데이터 인프라 최상급","교육비 지원"]'::jsonb, 'published', now() + interval '20 days'),
('toss-security', (SELECT id FROM companies WHERE slug='toss'), 'Security Engineer', '보안', '서울 강남구', '하이브리드', '경력 3년+', '학사 이상', '토스 금융 서비스의 보안 인프라를 설계합니다.', '수천만 사용자의 금융 데이터를 보호합니다.', '["보안 아키텍처 설계","취약점 분석","인시던트 대응"]'::jsonb, '["보안 실무 3년+","금융 보안 이해","코드 리뷰 역량"]'::jsonb, '["업계 최고 보상","자율출퇴근"]'::jsonb, 'published', now() + interval '30 days'),
('baemin-backend', (SELECT id FROM companies WHERE slug='baemin'), 'Backend Engineer (주문시스템)', '개발', '서울 송파구', '하이브리드', '경력 3년+', '학사 이상', '배달의민족 주문 시스템의 백엔드를 개발합니다.', '초당 수만 건의 주문을 처리하는 대규모 시스템을 설계합니다.', '["주문/결제 시스템 개발","대규모 트래픽 처리","MSA 설계"]'::jsonb, '["Java/Kotlin 숙련","Spring 생태계","대규모 트래픽 경험"]'::jsonb, '["주 35시간","배민 식대","도서비"]'::jsonb, 'published', now() + interval '18 days'),
