('baemin-marketing', (SELECT id FROM companies WHERE slug='baemin'), '브랜드 마케터', '마케팅', '서울 송파구', '하이브리드', '경력 3년+', '학사 이상', '배달의민족 브랜드 캠페인을 기획하고 실행합니다.', '배민다운 크리에이티브로 사랑받는 브랜드를 만듭니다.', '["브랜드 캠페인 기획","콘텐츠 전략 수립","외부 파트너 협업"]'::jsonb, '["브랜드 마케팅 경험 3년+","크리에이티브 기획력","트렌드 감각"]'::jsonb, '["주 35시간","배민 식대"]'::jsonb, 'published', now() + interval '15 days'),
