('kakao-devops', (SELECT id FROM companies WHERE slug='kakao'), 'DevOps Engineer', '개발', '경기 판교', '하이브리드', '경력 3년+', '학사 이상', '카카오 서비스의 CI/CD와 인프라를 운영합니다.', '안정적인 서비스 배포와 운영 자동화를 담당합니다.', '["CI/CD 파이프라인 구축","Kubernetes 운영","모니터링 시스템"]'::jsonb, '["DevOps 경험 3년+","Kubernetes, Terraform","Linux 시스템"]'::jsonb, '["자유로운 근무","장비 선택","교육비"]'::jsonb, 'published', now() + interval '28 days'),
